import { Check } from "lucide-react";
import type { BackendStep } from "@/lib/api";

interface JobProgressProps {
  step: BackendStep | null;
  progress: number;
}

interface UiStep {
  key: string;
  label: string;
  backendSteps: BackendStep[];
}

const UI_STEPS: UiStep[] = [
  { key: "ingest", label: "Reading source material", backendSteps: ["ingest"] },
  { key: "finance", label: "Extracting key facts", backendSteps: ["finance"] },
  { key: "scripter", label: "Writing voiceover script", backendSteps: ["scripter"] },
  { key: "tts", label: "Recording narration", backendSteps: ["tts"] },
  { key: "hera", label: "Generating motion graphics", backendSteps: ["hera_plan", "hera_render"] },
  { key: "compose", label: "Rendering final video", backendSteps: ["compose"] },
];

const ORDER: BackendStep[] = ["ingest", "finance", "scripter", "tts", "hera_plan", "hera_render", "compose", "done"];

function stepState(uiStep: UiStep, current: BackendStep | null): "pending" | "running" | "done" {
  if (!current) return "pending";
  const currentIdx = ORDER.indexOf(current);
  const stepMaxIdx = Math.max(...uiStep.backendSteps.map((s) => ORDER.indexOf(s)));
  if (current === "done") return "done";
  if (uiStep.backendSteps.includes(current)) return "running";
  if (currentIdx > stepMaxIdx) return "done";
  return "pending";
}

export const JobProgress = ({ step, progress }: JobProgressProps) => {
  return (
    <div>
      <ul className="space-y-3">
        {UI_STEPS.map((s) => {
          const state = stepState(s, step);
          return (
            <li key={s.key} className="flex items-center gap-3">
              <span className="inline-flex h-6 w-6 items-center justify-center shrink-0">
                {state === "done" && (
                  <span className="h-6 w-6 rounded-full bg-accent text-accent-foreground inline-flex items-center justify-center">
                    <Check className="h-3.5 w-3.5" aria-hidden />
                  </span>
                )}
                {state === "running" && (
                  <span className="relative inline-flex h-6 w-6 items-center justify-center">
                    <span className="absolute inline-flex h-3 w-3 rounded-full bg-accent/40 animate-ping" />
                    <span className="relative inline-flex h-3 w-3 rounded-full bg-accent" />
                  </span>
                )}
                {state === "pending" && (
                  <span className="h-3 w-3 rounded-full bg-gray-200" />
                )}
              </span>
              <span
                className={`text-sm ${
                  state === "pending"
                    ? "text-secondary"
                    : state === "running"
                      ? "text-primary font-medium"
                      : "text-primary"
                }`}
              >
                {s.label}
              </span>
            </li>
          );
        })}
      </ul>

      <div className="mt-8">
        <div className="flex items-center justify-between mb-2">
          <span className="text-xs text-secondary uppercase tracking-wider font-semibold">
            Progress
          </span>
          <span className="font-mono text-xs text-secondary">{Math.round(progress)}%</span>
        </div>
        <div className="w-full bg-gray-200 rounded-full h-2 overflow-hidden">
          <div
            className="h-2 bg-accent rounded-full transition-all duration-500 ease-out"
            style={{ width: `${Math.max(0, Math.min(100, progress))}%` }}
          />
        </div>
      </div>
    </div>
  );
};

export default JobProgress;

import { Link } from "react-router-dom";
import { Download } from "lucide-react";

interface JobResultProps {
  videoUrl: string;
}

export const JobResult = ({ videoUrl }: JobResultProps) => {
  return (
    <div>
      <video
        controls
        src={videoUrl}
        className="w-full rounded-lg bg-primary"
        preload="metadata"
      >
        Your browser does not support the video tag.
      </video>

      <div className="mt-6 flex flex-col sm:flex-row gap-3">
        <a
          href={videoUrl}
          download
          className="inline-flex items-center justify-center gap-2 bg-accent text-accent-foreground rounded-lg px-5 py-3 font-medium hover:bg-accent/90 transition-colors"
        >
          <Download className="h-4 w-4" aria-hidden />
          Download MP4
        </a>
        <Link
          to="/dashboard"
          className="inline-flex items-center justify-center border border-border text-primary rounded-lg px-5 py-3 font-medium hover:bg-muted transition-colors"
        >
          Generate another
        </Link>
      </div>
    </div>
  );
};

export default JobResult;

from __future__ import annotations

import asyncio
import shutil
import time
from pathlib import Path

from fastapi import FastAPI, File, Form, HTTPException, UploadFile
from fastapi import Request
from fastapi.middleware.cors import CORSMiddleware
from fastapi.responses import JSONResponse
from fastapi.responses import FileResponse

from app.config import get_settings
from app.integrations.tavily import TavilyClient
from app.jobs import JobStore
from app.pipeline import run_pipeline
from app.schemas import GenerateResponse, JobStatus, JobStep

settings = get_settings()
job_store = JobStore()
app = FastAPI(title="CorpuScan API")
REQUEST_TIMEOUT_SECONDS = 240
STALE_TMP_AGE_SECONDS = 30 * 60
TMP_ROOT = Path("/tmp")

app.add_middleware(
    CORSMiddleware,
    allow_origins=settings.cors_origins_list,
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)


@app.middleware("http")
async def request_timeout_middleware(request: Request, call_next):
    try:
        return await asyncio.wait_for(call_next(request), timeout=REQUEST_TIMEOUT_SECONDS)
    except TimeoutError:
        return JSONResponse(status_code=504, content={"detail": "Request timed out."})


@app.on_event("startup")
async def startup_cleanup() -> None:
    cleanup_stale_tmp_jobs()


@app.on_event("shutdown")
async def shutdown_cleanup() -> None:
    cleanup_stale_tmp_jobs()


@app.get("/health")
async def health() -> dict[str, bool]:
    return {"ok": True}


@app.post("/generate", response_model=GenerateResponse)
async def generate(
    file: UploadFile | None = File(default=None),
    url: str | None = Form(default=None),
    query: str | None = Form(default=None),
) -> GenerateResponse:
    provided_count = sum(1 for value in [file, url, query] if value)
    if provided_count != 1:
        raise HTTPException(status_code=400, detail="Provide exactly one input: file, url, or query.")

    source_text = await _resolve_source_text(file=file, url=url, query=query)
    if not source_text.strip():
        raise HTTPException(status_code=400, detail="Could not extract text from the provided source.")

    job_id = job_store.create()
    job_store.update_step(job_id, step=JobStep.INGEST, progress=10)
    asyncio.create_task(run_pipeline(job_store, job_id, source_text))
    return GenerateResponse(job_id=job_id)


@app.get("/jobs/{job_id}", response_model=JobStatus)
async def get_job(job_id: str) -> JobStatus:
    job = job_store.get(job_id)
    if job is None:
        raise HTTPException(status_code=404, detail="Job not found.")
    return job.to_status()


@app.get("/jobs/{job_id}/video")
async def get_job_video(job_id: str, download: int = 0) -> FileResponse:
    video_path = Path("/tmp") / job_id / "final.mp4"
    if not video_path.exists():
        raise HTTPException(status_code=404, detail="Video not found.")
    headers: dict[str, str] = {}
    if download == 1:
        headers["Content-Disposition"] = f'attachment; filename="{job_id}.mp4"'
    return FileResponse(video_path, media_type="video/mp4", headers=headers)


async def _resolve_source_text(
    *, file: UploadFile | None, url: str | None, query: str | None
) -> str:
    if file is not None:
        from app.ingest import extract_pdf_text

        file_bytes = await file.read()
        return extract_pdf_text(file_bytes)

    tavily_client = TavilyClient(api_key=settings.tavily_api_key)
    if url:
        return await tavily_client.extract(url)
    if query:
        results = await tavily_client.search(query)
        if not results:
            raise HTTPException(status_code=404, detail="No search results found for the provided query.")
        return await tavily_client.extract(results[0].url)
    return ""


def cleanup_stale_tmp_jobs(now_ts: float | None = None) -> None:
    now = now_ts if now_ts is not None else time.time()
    if not TMP_ROOT.exists():
        return
    for child in TMP_ROOT.iterdir():
        if not child.is_dir():
            continue
        try:
            age_seconds = now - child.stat().st_mtime
            if age_seconds > STALE_TMP_AGE_SECONDS:
                shutil.rmtree(child, ignore_errors=True)
        except OSError:
            continue

from __future__ import annotations

from functools import lru_cache

from pydantic import Field
from pydantic_settings import BaseSettings, SettingsConfigDict


class Settings(BaseSettings):
    model_config = SettingsConfigDict(env_file=".env", env_file_encoding="utf-8", extra="ignore")

    gemini_api_key: str = Field(default="")
    tavily_api_key: str = Field(default="")
    elevenlabs_api_key: str = Field(default="")
    elevenlabs_voice_id: str = Field(default="")
    hera_api_key: str = Field(default="")
    hera_base_url: str = Field(default="https://api.hera.video/v1")
    cors_origins: str = Field(
        default="http://localhost:5173,https://corpuscan.vercel.app",
    )

