from __future__ import annotations

import json

from app.agents._prompts import load_prompt
from app.integrations.gemini import GeminiClient
from app.schemas import Scene, SentenceTiming

REQUIRED_TOP_LEVEL_KEYS = {"duration", "fps", "resolution", "background", "elements"}
ALLOWED_ELEMENT_TYPES = {
    "kinetic_text",
    "number_countup",
    "bar_chart",
    "line_chart",
    "callout",
    "underline",
    "divider",
}


async def run_hera_agent(
    *,
    scene: Scene,
    sentence_timings_for_scene: list[SentenceTiming],
    gemini_client: GeminiClient,
) -> dict[str, object]:
    prompt = load_prompt("hera")
    timings_payload = [
        {
            "index": idx,
            "text": item.sentence,
            "start": item.start_seconds,
            "end": item.end_seconds,
        }
        for idx, item in enumerate(sentence_timings_for_scene)
    ]
    user = prompt.user_template.format(
        scene_title=scene.title,
        scene_narration=scene.narration,
        timings_json=json.dumps(timings_payload, indent=2),
    )
    response_text = await gemini_client.generate(
        system=prompt.system,
        user=user,
        model=prompt.model,
        temperature=prompt.temperature,
        response_mime_type=prompt.response_mime_type,
    )
    parsed = json.loads(response_text)
    if not isinstance(parsed, dict):
        raise ValueError("Hera response must be a JSON object.")
    validate_hera_spec(parsed)
    return parsed


def validate_hera_spec(spec: dict[str, object]) -> None:
    missing = [key for key in REQUIRED_TOP_LEVEL_KEYS if key not in spec]
    if missing:
        raise ValueError(f"Hera spec missing required top-level keys: {', '.join(missing)}")

    duration = spec.get("duration")
    if not isinstance(duration, (int, float)) or duration <= 0:
        raise ValueError("Hera spec 'duration' must be a positive number.")

    elements = spec.get("elements")
    if not isinstance(elements, list) or not elements:
        raise ValueError("Hera spec 'elements' must be a non-empty list.")

    for idx, element in enumerate(elements):
        if not isinstance(element, dict):
            raise ValueError(f"Element {idx} is not an object.")
        element_type = element.get("type")
        if element_type not in ALLOWED_ELEMENT_TYPES:
            raise ValueError(
                f"Element {idx} has unsupported type {element_type!r}; "
                f"allowed: {sorted(ALLOWED_ELEMENT_TYPES)}"
            )
        start = element.get("start")
        end = element.get("end")
        if not isinstance(start, (int, float)) or not isinstance(end, (int, float)):
            raise ValueError(f"Element {idx} missing numeric start/end.")
        if not 0 <= start < end <= float(duration) + 0.001:
            raise ValueError(
                f"Element {idx} timing out of range: 0 <= start < end <= duration."
            )

